 AND time_archived IS NULL''\n48: ).all(projectId);\n49: \n50: if (excludeSessionId) {\n51:   sessions = sessions.filter(s => s.id !== excludeSessionId);\n52: }\n53: \n54: const sessionIds = sessions.map(s => s.id);\n55: \n56: // 统计每个会话的消息数量\n57: const messageCounts = sessionIds.length > 0\n58:   ? db.prepare(\n59:       `SELECT session_id, COUNT(*) as count FROM message WHERE session_id IN (${sessionIds.map(() => ''?'').join('','')}) GROUP BY session_id`\n60:     ).all(...sessionIds)\n61:   : [];\n62: \n63: const messageCountMap = new Map(messageCounts.map(m => [m.session_id, m.count]));\n64: \n65: const messages = sessionIds.length > 0\n66:   ? db.prepare(\n67:       `SELECT * FROM message WHERE session_id IN (${sessionIds.map(() => ''?'').join('','')})`\n68:     ).all(...sessionIds)\n69:   : [];\n70: \n71: const parts = sessionIds.length > 0\n72:   ? db.prepare(\n73:       `SELECT * FROM part WHERE session_id IN (${sessionIds.map(() => ''?'').join('','')})`\n74:     ).all(...sessionIds)\n75:   : [];\n76: \n77: const todos = sessionIds.length > 0\n78:   ? db.prepare(\n79:       `SELECT * FROM todo WHERE session_id IN (${sessionIds.map(() => ''?'').join('','')})`\n80:     ).all(...sessionIds)\n81:   : [];\n82: \n83: const sessionMessages = sessionIds.length > 0\n84:   ? db.prepare(\n85:       `SELECT * FROM session_message WHERE session_id IN (${sessionIds.map(() => ''?'').join('','')})`\n86:     ).all(...sessionIds)\n87:   : [];\n88: \n89: const eventSequences = sessionIds.length > 0\n90:   ? db.prepare(\n91:       `SELECT * FROM event_sequence WHERE aggregate_id IN (${sessionIds.map(() => ''?'').join('','')})`\n92:     ).all(...sessionIds)\n93:   : [];\n94: \n95: const projectDirs = db.prepare(\n96:   ''SELECT * FROM project_directory WHERE project_id = ?''\n97: ).all(projectId);\n98: \n99: db.close();\n100: \n101: const lines = [];\n102: lines.push(''-- OPENCODE_CONVERSATION_BACKUP'');\n103: lines.push(''-- version: 1'');\n104: lines.push(`-- export_time: ${new 